import http.server, json, base64, os, io, socket, tempfile
from datetime import datetime
from urllib.parse import urlparse

PORT = 8080
LOGO_B64 = ''
CARDIO_B64 = ''

def get_ip():
    s = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
    try:
        s.connect(("8.8.8.8", 80))
        return s.getsockname()[0]
    except:
        return "127.0.0.1"
    finally:
        s.close()

def fmt_fecha(iso):
    if not iso: return ""
    meses = ["enero","febrero","marzo","abril","mayo","junio","julio","agosto",
             "septiembre","octubre","noviembre","diciembre"]
    try:
        y, mo, d = iso.split("-")
        return "San Juan, " + str(int(d)) + " de " + meses[int(mo)-1] + " del " + y
    except:
        return iso

def next_year(iso):
    if not iso: return ""
    try:
        d = datetime.strptime(iso, "%Y-%m-%d")
        return d.replace(year=d.year+1).strftime("%d/%m/%Y")
    except:
        return ""

_TMP = []

def add_logo_to_ws(ws, w=80, h=40):
    try:
        from openpyxl.drawing.image import Image as XLImg
        raw = base64.b64decode(LOGO_B64)
        suf = ".jpg" if raw[:2] == b"\xff\xd8" else ".png"
        tmp = tempfile.NamedTemporaryFile(suffix=suf, delete=False)
        tmp.write(raw); tmp.flush(); tmp.close()
        _TMP.append(tmp.name)
        img = XLImg(tmp.name)
        img.width = w; img.height = h; img.anchor = "A1"
        ws.add_image(img)
    except:
        pass

def cleanup_tmp():
    while _TMP:
        try: os.unlink(_TMP.pop())
        except: pass

AZ  = "1A8FC1"
AZD = "0D6A96"
AZL = "E8F5FC"
WHT = "FFFFFF"
GRY = "F8FAFC"
GN  = "16A34A"
RD  = "DC2626"
OR  = "D97706"
MU  = "64748B"

def mkC(ws):
    from openpyxl.styles import Font, PatternFill, Alignment
    def C(r,c,val="",bold=False,sz=10,col="1E293B",bg=None,align="left",wrap=False,fmt=None):
        cell = ws.cell(row=r,column=c,value=val)
        cell.font = Font(name="Calibri",size=sz,bold=bold,color=col)
        cell.alignment = Alignment(horizontal=align,vertical="center",wrap_text=wrap)
        if bg: cell.fill = PatternFill("solid",fgColor=bg)
        if fmt: cell.number_format = fmt
        return cell
    return C

def fill_cardio(d):
    import openpyxl
    raw = base64.b64decode(CARDIO_B64)
    wb = openpyxl.load_workbook(io.BytesIO(raw))
    ws = wb["Hoja1"]
    def sc(a,v):
        if v is not None and str(v).strip() not in ("","nan"): ws[a]=v
    def scn(a,v):
        try:
            f=float(v)
            if f==f: ws[a]=f
        except: pass
    sc("F6",  fmt_fecha(d.get("fe","")))
    sc("D9",  d.get("inst",""))
    sc("D10", d.get("fe",""))
    sc("D13", d.get("ma",""))
    sc("D14", d.get("mo",""))
    sc("D15", d.get("se",""))
    scn("D53", d.get("n1_esp","100"))
    scn("D54", d.get("n2_esp","200"))
    scn("D55", d.get("emax_esp","360"))
    scn("D56", d.get("pe_esp","200"))
    scn("F52", d.get("e_min",""))
    scn("F53", d.get("n1",""))
    scn("F54", d.get("n2",""))
    scn("F55", d.get("emax_res",""))
    scn("F56", d.get("pe",""))
    scn("F57", d.get("tc",""))
    for i,v in enumerate(d.get("rep",[])):
        scn("F"+str(63+i), v)
    for i,v in enumerate(d.get("bat",[])):
        scn("E"+str(78+i), v)
    sc("E99",  d.get("fo","OK"))
    scn("E100", d.get("r60",""))
    scn("E101", d.get("r120",""))
    scn("E102", d.get("ab",""))
    scn("E103", d.get("aa",""))
    scn("E108", d.get("si",""))
    scn("E109", d.get("re2",""))
    sc("B114", d.get("obs",""))
    sc("B130", d.get("tecnico",""))
    buf = io.BytesIO(); wb.save(buf); buf.seek(0)
    return buf.read()

def gen_ecg(d):
    import openpyxl
    wb = openpyxl.Workbook(); ws = wb.active; ws.title = "INFORME"
    ws.column_dimensions["A"].width = 3
    ws.column_dimensions["B"].width = 32
    ws.column_dimensions["C"].width = 8
    ws.column_dimensions["D"].width = 8
    ws.column_dimensions["E"].width = 22
    ws.column_dimensions["F"].width = 14
    ws.row_dimensions[1].height = 42
    C = mkC(ws)
    # ---- LOGO (A1) + HEADER ----
    add_logo_to_ws(ws, 90, 42)
    reg = d.get("reg","")
    ws.merge_cells("C1:D1")
    C(1,3,"SOLUCIONES ELECTROMÉDICAS",True,11,AZD,AZL,align="center")
    C(1,5,"REGISTRO N°"+str(reg) if reg else "REGISTRO",True,10,WHT,AZD,align="center")
    C(2,3,"Mail: solucioneselectromedicassj@gmail.com",False,8,MU)
    ws.merge_cells("C2:F2")
    C(3,3,"Tel: 264 4474932",False,8,MU)
    ws.merge_cells("C3:F3")
    # ---- TITULO ----
    ws.merge_cells("B4:F4")
    C(4,2,"Informe de Verificación de Electrocardiografo",True,12,AZD,AZL,align="center")
    ws.row_dimensions[4].height = 18
    # ---- INFO EQUIPO ----
    row = 5
    for lbl,val in [("Equipo",d.get("ma","").upper()),("Modelo",d.get("mo","")),
                    ("Numero de Serie",d.get("se","")),("Institucion",d.get("inst",""))]:
        C(row,2,lbl,True,9,AZD,GRY)
        ws.merge_cells("C"+str(row)+":F"+str(row))
        C(row,3,val,False,10,"1E293B")
        ws.row_dimensions[row].height = 15
        row += 1
    # ---- COLUMNA HEADER ----
    C(row,2,"Especificación de trabajo",True,9,AZD,AZL)
    ws.merge_cells("B"+str(row)+":D"+str(row))
    C(row,5,"Conforme / No Conforme / No Aplica",False,8,MU,AZL)
    ws.merge_cells("E"+str(row)+":F"+str(row))
    ws.row_dimensions[row].height = 14; row += 1
    def sec(r,title):
        ws.merge_cells("B"+str(r)+":F"+str(r))
        C(r,2,title,True,10,WHT,AZD,align="center")
        ws.row_dimensions[r].height = 15
    def item(r,label,key):
        bg = GRY if r%2==0 else WHT
        ws.merge_cells("B"+str(r)+":D"+str(r))
        C(r,2,label,False,9,"1E293B",bg)
        val = d.get(key,"No Aplica")
        col = GN if val=="Conforme" else (RD if val=="No Conforme" else OR)
        ws.merge_cells("E"+str(r)+":F"+str(r))
        C(r,5,val,True,9,col,bg)
        ws.row_dimensions[r].height = 14
    sec(row,"Estado general"); row+=1
    for lbl,k in [("Inspeccion visual","iv"),("Estado de cables","cb"),
                  ("Estado de perillas","per"),("Estado de pinzas","pi"),("Estado de bateria","ba")]:
        item(row,lbl,k); row+=1
    sec(row,"Seguimiento de Frecuencia Cardiaca"); row+=1
    for lbl,k in [("60 bpm","fc60"),("80 bpm","fc80"),("120 bpm","fc120")]:
        item(row,lbl,k); row+=1
    sec(row,"Tipo de Onda"); row+=1
    for lbl,k in [("Normal","on"),("Supraventricular","os"),("Fibrilacion ventricular","of"),
                  ("Flutter auricular","ofl"),("Triangular","ot"),("Senoidal","osen"),("Cuadrada","oc")]:
        item(row,lbl,k); row+=1
    sec(row,"Amplitud"); row+=1
    for lbl,k in [("0.5 mV","a05"),("1 mV","a1"),("2 mV","a2")]:
        item(row,lbl,k); row+=1
    row+=1
    sec(row,"Datos de equipos analizadores"); row+=1
    pt = d.get("patron","")
    if pt:
        for line in pt.split("\n"):
            if line.strip():
                ws.merge_cells("B"+str(row)+":F"+str(row))
                C(row,2,line.strip(),False,9,"1E293B"); row+=1
    row+=1
    obs = d.get("obs","")
    if obs:
        sec(row,"Informe de hallazgos"); row+=1
        ws.merge_cells("B"+str(row)+":F"+str(row))
        C(row,2,obs,False,9,"1E293B",wrap=True); row+=2
    sec(row,"Mantenimiento"); row+=1
    C(row,2,"Actual",True,9,AZD,GRY)
    C(row,5,d.get("fe",""),False,9,"1E293B"); row+=1
    C(row,2,"Sugerencia de proximo mantenimiento",True,9,AZD,GRY)
    C(row,5,next_year(d.get("fe","")),False,9,"1E293B"); row+=2
    ws.merge_cells("B"+str(row)+":F"+str(row))
    C(row,2,"ENCARGADO DEL MANTENIMIENTO",True,10,WHT,AZD,align="center"); row+=1
    ws.merge_cells("B"+str(row)+":F"+str(row))
    C(row,2,d.get("tecnico",""),False,11,"1E293B",align="center")
    buf=io.BytesIO(); wb.save(buf); cleanup_tmp(); buf.seek(0)
    return buf.read()

def gen_monitor(d):
    import openpyxl
    wb = openpyxl.Workbook(); ws = wb.active; ws.title = "INFORME"
    ws.column_dimensions["A"].width = 3
    ws.column_dimensions["B"].width = 20
    ws.column_dimensions["C"].width = 8
    ws.column_dimensions["D"].width = 18
    ws.column_dimensions["E"].width = 5
    ws.column_dimensions["F"].width = 18
    ws.column_dimensions["G"].width = 22
    ws.column_dimensions["H"].width = 14
    ws.row_dimensions[1].height = 42
    C = mkC(ws)
    add_logo_to_ws(ws, 90, 42)
    reg = d.get("reg","")
    ws.merge_cells("C1:F1")
    C(1,3,"SOLUCIONES ELECTROMÉDICAS",True,11,AZD,AZL,align="center")
    C(1,7,"REGISTRO N°"+str(reg) if reg else "REGISTRO",True,10,WHT,AZD,align="center")
    C(2,3,"Tel: 264 4474932 / 264 4802568",False,8,MU)
    ws.merge_cells("C2:H2")
    C(3,3,"Mail: solucioneselectromedicassj@gmail.com",False,8,MU)
    ws.merge_cells("C3:H3")
    ws.merge_cells("B4:H4")
    C(4,2,"VERIFICACION DE MONITOR MULTIPARAMETRICO",True,12,AZD,AZL,align="center")
    ws.row_dimensions[4].height = 18
    row = 5
    for lbl,val in [("Equipo",d.get("ma","")),("Modelo",d.get("mo","")),
                    ("Numero de Serie",d.get("se","")),("Institucion",d.get("inst",""))]:
        C(row,2,lbl,True,9,AZD,GRY)
        ws.merge_cells("C"+str(row)+":H"+str(row))
        C(row,3,val,False,10,"1E293B")
        ws.row_dimensions[row].height = 15; row+=1
    ws.merge_cells("B"+str(row)+":H"+str(row))
    C(row,2,"Observacion Fisica",True,10,WHT,AZD,align="center")
    ws.row_dimensions[row].height = 15; row+=1
    for lbl,key in [("Estado de Cables","obs_cb"),("Bateria","obs_ba"),("Estado General","obs_eg")]:
        bg = GRY if row%2==0 else WHT
        C(row,2,lbl,False,9,"1E293B",bg)
        ws.merge_cells("C"+str(row)+":E"+str(row))
        val=d.get(key,"Conforme")
        col=GN if val=="Conforme" else (RD if val=="No Conforme" else OR)
        ws.merge_cells("F"+str(row)+":H"+str(row))
        C(row,6,val,True,9,col,bg)
        ws.row_dimensions[row].height = 14; row+=1
    # Measurement table function
    def meas_table(start_row, punto):
        r = start_row
        C(r,2,"Tipo de dato",True,9,WHT,AZD)
        C(r,4,"Registro Patron",True,9,WHT,AZD,align="center")
        C(r,6,"Registro Medido",True,9,WHT,AZD,align="center")
        C(r,7,"Registro de Aceptacion",True,9,WHT,AZD,align="center")
        ws.row_dimensions[r].height = 15; r+=1
        n = str(punto)
        ROWS = [
            ("FC",   d.get("p"+n+"_fc_pat",""),   d.get("p"+n+"_fc_med",""),   "-"),
            ("FR",   d.get("p"+n+"_fr_pat",""),   d.get("p"+n+"_fr_med",""),   "-"),
            ("SpO2", d.get("p"+n+"_spo2_pat",""), d.get("p"+n+"_spo2_med",""), "95% - 99%"),
        ]
        pnis=str(d.get("p"+n+"_pni_s_pat",""))
        pnid=str(d.get("p"+n+"_pni_d_pat",""))
        pnism=str(d.get("p"+n+"_pni_s_med",""))
        pnidm=str(d.get("p"+n+"_pni_d_med",""))
        pni_pat=pnis+"/"+pnid if pnis and pnid else ""
        pni_med=pnism+"/"+pnidm if pnism and pnidm else ""
        ROWS.append(("PNI",pni_pat,pni_med,"-"))
        ROWS.append(("T1",d.get("p"+n+"_temp_pat",""),d.get("p"+n+"_temp_med",""),"-"))
        for i,(lbl,pat,med,acc) in enumerate(ROWS):
            bg = GRY if i%2==0 else WHT
            C(r,2,lbl,True,9,AZD,bg)
            C(r,4,pat,False,9,"1E293B",bg)
            C(r,6,med,True,9,"1E293B",bg)
            C(r,7,acc,False,8,MU,bg)
            ws.row_dimensions[r].height = 14; r+=1
        return r
    row = meas_table(row, 1)
    row = meas_table(row, 2)
    ws.merge_cells("B"+str(row)+":H"+str(row))
    C(row,2,"Patron",True,10,WHT,AZD,align="center")
    ws.row_dimensions[row].height = 15; row+=1
    pt = d.get("patron","")
    if pt:
        for line in pt.split("\n"):
            if line.strip():
                ws.merge_cells("B"+str(row)+":H"+str(row))
                C(row,2,line.strip(),False,9,"1E293B"); row+=1
    obs = d.get("obs","")
    if obs:
        row+=1
        ws.merge_cells("B"+str(row)+":H"+str(row))
        C(row,2,"Observaciones",True,10,WHT,AZD,align="center"); row+=1
        ws.merge_cells("B"+str(row)+":H"+str(row))
        C(row,2,obs,False,9,"1E293B",wrap=True); row+=1
    row+=1
    ws.merge_cells("B"+str(row)+":H"+str(row))
    C(row,2,"Mantenimiento",True,10,WHT,AZD,align="center")
    ws.row_dimensions[row].height = 15; row+=1
    C(row,2,"Actual",True,9,AZD,GRY)
    C(row,4,d.get("fe",""),False,9,"1E293B"); row+=1
    C(row,2,"Sugerencia de proximo mantenimiento",True,9,AZD,GRY)
    C(row,4,next_year(d.get("fe","")),False,9,"1E293B"); row+=2
    ws.merge_cells("B"+str(row)+":H"+str(row))
    C(row,2,"ENCARGADO DEL MANTENIMIENTO",True,10,WHT,AZD,align="center"); row+=1
    ws.merge_cells("B"+str(row)+":H"+str(row))
    C(row,2,d.get("tecnico",""),False,11,"1E293B",align="center")
    buf=io.BytesIO(); wb.save(buf); cleanup_tmp(); buf.seek(0)
    return buf.read()

